import json
import os
import socket
import time

DEFAULT_LOOKUP_TIMEOUT = 0.3
DEFAULT_STATE_SERVER_HOST = os.environ.get("GO2_STATE_SERVER_HOST", "127.0.0.1")
DEFAULT_STATE_SERVER_PORT = int(os.environ.get("GO2_STATE_SERVER_PORT", "8765"))


class StateReader:
    def __init__(
        self,
        lookup_timeout=DEFAULT_LOOKUP_TIMEOUT,
        host=DEFAULT_STATE_SERVER_HOST,
        port=DEFAULT_STATE_SERVER_PORT,
        socket_timeout=2.0,
    ):
        self.lookup_timeout = float(lookup_timeout)
        self.host = host
        self.port = int(port)
        self.socket_timeout = float(socket_timeout)

    def get_state(self):
        request = {
            "cmd": "get_state",
            "timeout_sec": self.lookup_timeout,
        }
        try:
            response = self._send_request(request)
        except OSError as exc:
            raise RuntimeError(
                "state_server_unreachable: 无法连接位姿服务。"
                f" host={self.host}, port={self.port}。"
                " 请先在独立终端启动 amcl_pose_server.py。"
            ) from exc

        if not isinstance(response, dict):
            raise RuntimeError("state_server_invalid_response")

        if not response.get("success", False):
            error = response.get("error", "unknown_error")
            detail = response.get("detail")
            if detail:
                raise RuntimeError(f"state_server_error: {error}: {detail}")
            raise RuntimeError(f"state_server_error: {error}")

        state = response.get("state")
        if not isinstance(state, dict):
            raise RuntimeError("state_server_missing_state")
        return state

    def _send_request(self, payload):
        # 每次请求短连接一次，避免主进程长期持有 ROS2 侧资源。
        with socket.create_connection(
            (self.host, self.port),
            timeout=self.socket_timeout,
        ) as conn:
            conn.settimeout(self.socket_timeout)
            message = json.dumps(payload, ensure_ascii=False) + "\n"
            conn.sendall(message.encode("utf-8"))

            buffer = b""
            while b"\n" not in buffer:
                chunk = conn.recv(4096)
                if not chunk:
                    break
                buffer += chunk

        if not buffer:
            raise RuntimeError("state_server_empty_response")

        return json.loads(buffer.decode("utf-8").strip())

    def close(self):
        return None


if __name__ == "__main__":
    getter = StateReader()
    try:
        print("state client started...")
        while True:
            state = getter.get_state()
            print("\n==================== robot state ====================")
            print(f"frame_id:    {state['frame_id']}")
            print(f"position:    {state['position']}")
            print(f"orientation: {state['orientation']}")
            print(f"yaw:         {state['yaw']}")
            print("====================================================")
            time.sleep(2.0)
    except KeyboardInterrupt:
        pass
